def max_subarray_dc(nums):
    def helper(l, r):
        if l == r: return nums[l]
        mid = (l + r) // 2
        left = helper(l, mid)
        right = helper(mid+1, r)
        # Cross sum
        ls = rs = float('-inf')
        s = 0
        for i in range(mid, l-1, -1):
            s += nums[i]; ls = max(ls, s)
        s = 0
        for i in range(mid+1, r+1):
            s += nums[i]; rs = max(rs, s)
        return max(left, right, ls + rs)
    return helper(0, len(nums)-1)

